diff --git a/packages/svelte/src/internal/client/reactivity/deriveds.js b/packages/svelte/src/internal/client/reactivity/deriveds.js
index d3123d24a..dd7b1db8d 100644
--- a/packages/svelte/src/internal/client/reactivity/deriveds.js
+++ b/packages/svelte/src/internal/client/reactivity/deriveds.js
@@ -15,7 +15,7 @@ import {
 import { equals, safe_equals } from './equality.js';
 import * as e from '../errors.js';
 import { destroy_effect } from './effects.js';
-import { inspect_effects, set_inspect_effects } from './sources.js';
+import { inspect_effects, set_inspect_effects, old_values } from './sources.js';
 import { get_stack } from '../dev/tracing.js';
 import { tracing_mode_flag } from '../../flags/index.js';
 import { component_context } from '../context.js';
@@ -176,6 +176,14 @@ export function update_derived(derived) {
 	var value = execute_derived(derived);

 	if (!derived.equals(value)) {
+		var old_value = derived.v;
+
+		if (is_destroying_effect) {
+			old_values.set(derived, value);
+		} else {
+			old_values.set(derived, old_value);
+		}
+
 		derived.v = value;
 		derived.wv = increment_write_version();
 	}
