import { flushSync } from 'svelte';
import { test } from '../../test';

export default test({
	async test({ assert, target, logs }) {
		const [button] = target.querySelectorAll('button');

		// Initial state: count = 0, double = 0
		// Click once: count becomes 1, double becomes 2
		// In teardown, we should see the OLD double value (0), not the new value (2)
		flushSync(() => {
			button.click();
		});

		assert.deepEqual(logs, ['teardown double:', 0]);

		logs.length = 0;

		// Click again: count becomes 2, double becomes 4
		// In teardown, we should see the OLD double value (2), not the new value (4)
		flushSync(() => {
			button.click();
		});

		assert.deepEqual(logs, ['teardown double:', 2]);
	}
});

